use regex::Regex;

#[test]
fn test_simple_regex() {
    let re = Regex::new("test").unwrap();
    assert!(re.is_match("test_file.rs"));
    assert!(!re.is_match("other.rs"));
}

#[test]
fn test_extension_regex() {
    let re = Regex::new(r"\.rs$").unwrap();
    assert!(re.is_match("main.rs"));
    assert!(!re.is_match("main.py"));
}

#[test]
fn test_case_insensitive() {
    let re = Regex::new("(?i)readme").unwrap();
    assert!(re.is_match("README.md"));
    assert!(re.is_match("readme.txt"));
}
